mapper.sql:
SELECT
ID,
JK_INFO,
SJSB_TYPE,
SJSB_STATUS,
SERVICE_ID,
SERVICE_FIELD_I,
SERVICE_FIELD_II,
SERVICE_FIELD_III,
REQUEST_PARAMETERS,
RETURN_RESULT,
FAIL_REASON,
REMARK,
CREATE_BY,
CREATE_BY_NAME,
CREATE_TIME
FROM
M_SJSB_LOG


        and ID = #{id}


        and JK_INFO = #{jkInfo}


        and SJSB_TYPE = #{sjsbType}


        and SJSB_STATUS = #{sjsbStatus}


        and SERVICE_ID = #{serviceId}


        and SERVICE_FIELD_I = #{serviceFieldI}


        and SERVICE_FIELD_II = #{serviceFieldIi}


        and SERVICE_FIELD_III = #{serviceFieldIii}


        and REQUEST_PARAMETERS = #{requestParameters}


        and RETURN_RESULT = #{returnResult}


        and FAIL_REASON = #{failReason}


        and REMARK = #{remark}


        and to_char(CREATE_TIME,'YYYY-MM-DD hh24:mi:ss') >= #{startTime}


        and to_char(CREATE_TIME,'YYYY-MM-DD hh24:mi:ss') < #{endTime}
